// Ens assegurem que el DOM esta carregat abans de manipular-lo
document.addEventListener('DOMContentLoaded', () => {

  // a) Modificar contingut de text
  const titolPrincipal = document.getElementById('titol-principal');
  titolPrincipal.textContent = 'Cataleg dinamic actualitzat amb JavaScript';

  const resum = document.getElementById('resum');
  resum.innerHTML = 
    '<strong>Benvinguts al nostre cataleg dinamic!</strong><br>' +
    'Ara actualitzem aquest contingut amb <em>JavaScript</em> i el DOM.';

  // b) Modificar atributs i data-*
  const enllacBotiga = document.getElementById('enllac-botiga');
  enllacBotiga.setAttribute('href', 'https://www.ioc.cat');
  enllacBotiga.setAttribute('title', "Obre la nova botiga de l'IOC");
  enllacBotiga.textContent = "Visitem la nova botiga de l'IOC";

  // Llegir data-preu del primer producte
  const primerProducte = document.querySelector('#llista-productes .producte');
  const preuOriginal = primerProducte.dataset.preu;
  console.log('Preu original:', preuOriginal);

  // Actualitzar data-preu a 14.5
  primerProducte.dataset.preu = '14.5';
  primerProducte.querySelector('.preu-producte').textContent = '14,50 €';

  // c) Crear i inserir nous elements
  const llistaProductes = document.getElementById('llista-productes');

  function crearProducte(nom, preuNumeric) {
    const li = document.createElement('li');
    li.classList.add('producte');
    li.dataset.preu = String(preuNumeric);

    const strong = document.createElement('strong');
    strong.classList.add('nom-producte');
    strong.textContent = nom;

    const span = document.createElement('span');
    span.classList.add('preu-producte');
    span.textContent = preuNumeric.toFixed(2).replace('.', ',') + ' €';

    li.appendChild(strong);
    li.appendChild(document.createTextNode(' '));
    li.appendChild(span);
    return li;
  }

  llistaProductes.prepend(crearProducte('Producte al principi', 5.99));
  llistaProductes.append(crearProducte('Producte al final', 12.0));

  // d) Clonar elements amb cloneNode
  const plantilla = document.getElementById('plantilla-producte');
  if (plantilla) {
    const clon = plantilla.cloneNode(true);
    clon.removeAttribute('id');
    clon.querySelector('.nom-producte').textContent = 'Producte clonat';
    clon.querySelector('.preu-producte').textContent = '19,99 €';
    clon.dataset.preu = '19.99';
    llistaProductes.appendChild(clon);
  }

  // e) Eliminar i reemplaçar elements
  const banner = document.getElementById('banner');
  const missatgeBannerAntic = document.getElementById('missatge-banner');
  if (missatgeBannerAntic) missatgeBannerAntic.remove();

  const nouBanner = document.createElement('p');
  nouBanner.textContent = 'Banner actual: descompte del 20% en tots els productes!';
  banner.appendChild(nouBanner);

  const infoBanner = document.createElement('p');
  infoBanner.textContent = 'Aquesta promocio es limitada en el temps.';
  banner.insertBefore(infoBanner, nouBanner);
});

